import{_ as t,c as a,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"认证失败: 401 错误排查 | Antigravity Manager","description":"学习 Antigravity Manager 的代理认证机制，排查 401 未授权错误。按顺序检查 auth_mode、api_key 和 Header，理解 auto 模式规则和 /healthz 免检，避免 Header 优先级陷阱。","frontmatter":{"title":"认证失败: 401 错误排查 | Antigravity Manager","sidebarTitle":"认证失败","subtitle":"认证失败: 401 错误排查","description":"学习 Antigravity Manager 的代理认证机制，排查 401 未授权错误。按顺序检查 auth_mode、api_key 和 Header，理解 auto 模式规则和 /healthz 免检，避免 Header 优先级陷阱。","tags":["FAQ","Authentication","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),i={name:"lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function s(d,e,l,n,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_401-auth-failure-check-auth-mode-first-then-headers" tabindex="-1">401/Auth Failure: Check auth_mode First, Then Headers <a class="header-anchor" href="#_401-auth-failure-check-auth-mode-first-then-headers" aria-label="Permalink to &quot;401/Auth Failure: Check auth_mode First, Then Headers&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Determine within 3 minutes whether 401 is blocked by Antigravity Tools auth middleware</li><li>Understand the &quot;effective value&quot; of the four <code>proxy.auth_mode</code> modes (especially <code>auto</code>) in your current configuration</li><li>Get requests through with the correct API Key Header (and avoid Header priority pitfalls)</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p>Your client receives a <code>401 Unauthorized</code> error when calling the local reverse proxy:</p><ul><li>Python/OpenAI SDK: throws <code>AuthenticationError</code></li><li>curl: returns <code>HTTP/1.1 401 Unauthorized</code></li><li>HTTP clients: response status code 401</li></ul><h2 id="what-is-401-auth-failure" tabindex="-1">What is 401/Auth Failure? <a class="header-anchor" href="#what-is-401-auth-failure" aria-label="Permalink to &quot;What is 401/Auth Failure?&quot;">​</a></h2><p><strong>401 Unauthorized</strong> in Antigravity Tools most commonly means: the proxy has authentication enabled (determined by <code>proxy.auth_mode</code>), but the request either doesn&#39;t carry the correct API Key, or carries a higher-priority but mismatching Header, causing <code>auth_middleware()</code> to directly return 401.</p><div class="info custom-block"><p class="custom-block-title">First confirm whether &quot;proxy is blocking you&quot;</p><p>Upstream platforms may also return 401, but this FAQ only handles &quot;401 caused by proxy authentication&quot;. You can quickly distinguish this with <code>/healthz</code> below.</p></div><h2 id="quick-troubleshooting-follow-this-order" tabindex="-1">Quick Troubleshooting (Follow This Order) <a class="header-anchor" href="#quick-troubleshooting-follow-this-order" aria-label="Permalink to &quot;Quick Troubleshooting (Follow This Order)&quot;">​</a></h2><h3 id="step-1-use-healthz-to-determine-whether-auth-is-blocking-you" tabindex="-1">Step 1: Use <code>/healthz</code> to Determine &quot;Whether Auth is Blocking You&quot; <a class="header-anchor" href="#step-1-use-healthz-to-determine-whether-auth-is-blocking-you" aria-label="Permalink to &quot;Step 1: Use `/healthz` to Determine &quot;Whether Auth is Blocking You&quot;&quot;">​</a></h3><p><strong>Why</strong><code>all_except_health</code> allows <code>/healthz</code> through but blocks other routes; this helps you quickly locate whether 401 comes from the proxy authentication layer.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Without any auth Header</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>You should see</strong></p><ul><li>When <code>auth_mode=all_except_health</code> (or <code>auto</code> with <code>allow_lan_access=true</code>): usually returns <code>200</code></li><li>When <code>auth_mode=strict</code>: returns <code>401</code></li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code> is GET at the routing layer</p><p>The proxy registers <code>GET /healthz</code> in routes (see <code>src-tauri/src/proxy/server.rs</code>).</p></div><hr><h3 id="step-2-confirm-the-effective-value-of-auth-mode-especially-auto" tabindex="-1">Step 2: Confirm the &quot;Effective Value&quot; of <code>auth_mode</code> (Especially <code>auto</code>) <a class="header-anchor" href="#step-2-confirm-the-effective-value-of-auth-mode-especially-auto" aria-label="Permalink to &quot;Step 2: Confirm the &quot;Effective Value&quot; of `auth_mode` (Especially `auto`)&quot;">​</a></h3><p><strong>Why</strong><code>auto</code> is not an &quot;independent policy&quot;—it calculates the actual mode to execute based on <code>allow_lan_access</code>.</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>Additional Condition</th><th>Effective Mode</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>You can check this in the GUI&#39;s API Proxy page</strong>: <code>Allow LAN Access</code> and <code>Auth Mode</code>.</p><hr><h3 id="step-3-confirm-api-key-is-not-empty-and-you-re-using-the-same-value" tabindex="-1">Step 3: Confirm <code>api_key</code> is Not Empty and You&#39;re Using the Same Value <a class="header-anchor" href="#step-3-confirm-api-key-is-not-empty-and-you-re-using-the-same-value" aria-label="Permalink to &quot;Step 3: Confirm `api_key` is Not Empty and You&#39;re Using the Same Value&quot;">​</a></h3><p><strong>Why</strong> When auth is enabled, if <code>proxy.api_key</code> is empty, <code>auth_middleware()</code> will directly reject all requests and log an error.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>You should see</strong></p><ul><li>In the API Proxy page, you can see a key starting with <code>sk-</code> (default value is auto-generated by <code>ProxyConfig::default()</code>)</li><li>After clicking &quot;Regenerate/Edit&quot; and saving, external requests immediately validate with the new key (no restart needed)</li></ul><hr><h3 id="step-4-try-with-the-simplest-header-first-don-t-use-complex-sdks-yet" tabindex="-1">Step 4: Try with the Simplest Header First (Don&#39;t Use Complex SDKs Yet) <a class="header-anchor" href="#step-4-try-with-the-simplest-header-first-don-t-use-complex-sdks-yet" aria-label="Permalink to &quot;Step 4: Try with the Simplest Header First (Don&#39;t Use Complex SDKs Yet)&quot;">​</a></h3><p><strong>Why</strong> The middleware reads <code>Authorization</code> first, then <code>x-api-key</code>, then <code>x-goog-api-key</code>. If you send multiple Headers at once and the first one is wrong, even if the later ones are correct, they won&#39;t be used.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Recommended format: Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>You should see</strong>: <code>HTTP/1.1 200 OK</code> (or at least no longer 401)</p><div class="info custom-block"><p class="custom-block-title">Proxy Authorization compatibility details</p><p><code>auth_middleware()</code> strips the <code>Authorization</code> value once using the <code>Bearer </code> prefix; if there&#39;s no <code>Bearer </code> prefix, it uses the entire value as the key for comparison. Documentation still recommends <code>Authorization: Bearer &lt;key&gt;</code> (more compliant with common SDK conventions).</p></div><p><strong>If you must use <code>x-api-key</code></strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="common-pitfalls-all-real-issues-from-source-code" tabindex="-1">Common Pitfalls (All Real Issues from Source Code) <a class="header-anchor" href="#common-pitfalls-all-real-issues-from-source-code" aria-label="Permalink to &quot;Common Pitfalls (All Real Issues from Source Code)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Real Cause</th><th>How to Fix</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>, but localhost calls still get 401</td><td><code>allow_lan_access=true</code> causes <code>auto</code> to evaluate to <code>all_except_health</code></td><td>Disable <code>allow_lan_access</code>, or make the client carry the key</td></tr><tr><td>You think &quot;I clearly sent x-api-key&quot;, but still get 401</td><td>Also sent a mismatching <code>Authorization</code>, middleware prioritizes that</td><td>Remove extra Headers, keep only one you&#39;re sure is correct</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> still gets 401</td><td>Missing space after <code>Bearer</code>, cannot strip by <code>Bearer </code> prefix</td><td>Change to <code>Authorization: Bearer &lt;key&gt;</code></td></tr><tr><td>All requests get 401, logs show <code>api_key is empty</code></td><td><code>proxy.api_key</code> is empty</td><td>Regenerate/set a non-empty key in the GUI</td></tr></tbody></table><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>First use <code>/healthz</code> to locate whether 401 comes from the proxy authentication layer</li><li>Then confirm <code>auth_mode</code> (especially <code>auto</code>&#39;s effective mode)</li><li>Finally send only one definitely correct Header for verification (avoid Header priority pitfalls)</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../429-rotation/">429/Quota Errors: Correct Expectations for Account Rotation &amp; Misconceptions About Model Capacity Exhaustion</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Whether 429 is &quot;quota shortage&quot; or &quot;upstream rate limiting&quot;</li><li>Correct expectations for account rotation (when it automatically switches and when it doesn&#39;t)</li><li>Use configuration to reduce 429 probability</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>ProxyAuthMode enum</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key and defaults</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>auto mode parsing (effective_auth_mode)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>Auth middleware (Header extraction and priority, /healthz exemption, OPTIONS allow)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/auth.rs#L14-L77" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/auth.rs</code></a></td><td>14-77</td></tr><tr><td>/healthz route registration and middleware order</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>Auth documentation (modes and client conventions)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>Key Enums</strong>:</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>: Authentication modes</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>: Resolves <code>auto</code> to actual policy</li><li><code>auth_middleware()</code>: Executes authentication (includes Header extraction order and /healthz exemption)</li></ul></details>',45)])])}const y=t(i,[["render",s]]);export{p as __pageData,y as default};
